args.command:
node -e "
const Ajv = require('ajv').default || require('ajv');
const addFormats = require('ajv-formats');
const schema = require('./schema.json');
const manifest = require('./manifest.json');

let ajv;
try {
  const AjvClass = require('ajv').default || require('ajv');
  ajv = new AjvClass();
} catch(e) { ajv = new (require('ajv'))(); }

const validate = ajv.compile(schema);
const valid = validate(manifest);
if (valid) {
  console.log('VALID: manifest passes schema');
} else {
  console.log('INVALID:', JSON.stringify(validate.errors, null, 2));
}
console.log('manifest contents:', JSON.stringify(manifest, null, 2));
" 2>/dev/null || node -e "
// Try without ajv — just print and do manual checks
const manifest = require('./manifest.json');
console.log('manifest:', JSON.stringify(manifest, null, 2));

// Manual checks
const releaseOk = manifest.release === 'v2.4.0';
const isArray = Array.isArray(manifest.components);
const len = isArray && manifest.components.length === 3;
const order = isArray && manifest.components[0].name === 'catalog' && manifest.components[1].name === 'fetcher' && manifest.components[2].name === 'leaderboard';
const noExtra = isArray && manifest.components.every(c => Object.keys(c).length === 2 && 'name' in c && 'version' in c);
const versionPattern = isArray && manifest.components.every(c => /^[0-9]+\.[0-9]+\.[0-9]+$/.test(c.version));
const topKeys = Object.keys(manifest).join(',') === 'release,components';

console.log('release preserved (v2.4.0):', releaseOk);
console.log('components is array:', isArray);
console.log('exactly 3 items:', len);
console.log('correct order (catalog/fetcher/leaderboard):', order);
console.log('only name+version on each item:', noExtra);
console.log('version format valid:', versionPattern);
console.log('no extra top-level props:', topKeys);
"

